INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5iv0i00027sq1hrf8d38v','cmqwsfpam00015gq1re0l6z85','PPT-maker zondagsdienst','Muziek & eredienst','Jij verzorgt de presentatie tijdens de zondagsdienst — liedteksten, schriftlezingen en aankondigingen op het scherm.',NULL,'Een goede presentatie helpt de gemeente om mee te zingen en mee te lezen. Jij zorgt dat de dienst soepel verloopt en mensen niet worden afgeleid door fouten op het scherm.','Liedteksten en Bijbelgedeelten voorbereiden in PowerPoint of ProPresenter. Op zondagochtend op tijd aanwezig zijn om alles te testen. Tijdens de dienst de slides bedienen op het juiste moment.','Een keer meekijken hoe een huidige PPT-maker het doet.','Coördinator eredienst','eredienst@ngkmiddelharnis.nl','active','2026-07-08T14:06:45.378Z','2026-07-08T14:06:45.378Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5ixfq000b7sq1t6qtxu1p','cmqwsfpam00015gq1re0l6z85','Mentor tieners','Jeugd','Jij begeleidt een kleine groep tieners in hun geloofsgroei — als mentor, gespreksleider en vertrouwenspersoon.',NULL,'Tieners hebben volwassenen nodig die écht luisteren en hen serieus nemen in hun vragen over geloof en leven. Een mentor kan een blijvend verschil maken in deze fase.','Wekelijks of tweewekelijks bijeenkomen met een groepje tieners (4-6 personen). Bijbelstudie begeleiden, vragen bespreken, contact houden ook buiten de groep.','Een gesprek met de jeugdcoördinator over de aanpak en de groep.','Jeugdcoördinator','jeugd@ngkmiddelharnis.nl','active','2026-07-08T14:06:48.518Z','2026-07-08T14:06:48.518Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5iztk000k7sq17uepqy96','cmqwsfpam00015gq1re0l6z85','Leider kinderclub tijdens dienst','Jeugd','Jij begeleidt kinderen (4–12 jaar) tijdens de zondagsdienst met een eigen programma passend bij het thema van de preek.',NULL,'Kinderen leren op hun eigen niveau over God. Jij maakt kerk voor hen leuk, begrijpelijk en herkenbaar — dat legt een fundament voor de rest van hun leven.','Kinderprogramma voorbereiden en uitvoeren. Creatieve werkvormen, verhalen en activiteiten aanbieden. Kinderen ophalen uit de dienst en na afloop terugbrengen.','Een keer meedraaien als assistent bij de bestaande kinderclub.','Coördinator kinderwerk','kinderen@ngkmiddelharnis.nl','active','2026-07-08T14:06:51.608Z','2026-07-08T14:06:51.608Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5j2o1000s7sq18e122q87','cmqwsfpam00015gq1re0l6z85','Geluidscoördinator','Techniek','Jij coördineert het geluidsteam — roosters, training van vrijwilligers en het bewaken van de geluidskwaliteit tijdens diensten.',NULL,'Goed geluid is onzichtbaar als het klopt, en enorm storend als het niet klopt. Als coördinator zorg jij dat het team op orde is en dat de kwaliteit constant blijft.','Vrijwilligers inroosteren en trainen. Aanwezig bij bijzondere diensten. Overleggen met de predikant en muziekteam over wensen. Beheer van apparatuur.','Een gesprek met de huidige coördinator over overname van taken.','Technisch beheer','techniek@ngkmiddelharnis.nl','active','2026-07-08T14:06:55.297Z','2026-07-08T14:06:55.297Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5j7ag00107sq1x161ra3p','cmqwsfpam00015gq1re0l6z85','Geluidstechnicus','Techniek','Jij bedient de mengtafel tijdens de zondagsdienst en zorgt voor helder, gebalanceerd geluid voor gemeente en muzikanten.',NULL,'De gemeente moet de predikant en de muziek goed kunnen horen. Jij zorgt in de achtergrond dat alles klopt — onmisbaar voor elke dienst.','Op tijd aanwezig voor soundcheck. Microfoons instellen voor predikant, lezers en muzikanten. Tijdens de dienst het geluidsniveau bewaken en bijsturen.','Een keer meekijken naast een ervaren geluidstechnicus.','Geluidscoördinator','techniek@ngkmiddelharnis.nl','active','2026-07-08T14:07:01.288Z','2026-07-08T14:07:01.288Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5j9j100197sq13uc55w3o','cmqwsfpam00015gq1re0l6z85','Muzikant worship team','Muziek & eredienst','Jij speelt of zingt mee in het worship team tijdens de zondagsdienst en helpt de gemeente om God te loven.',NULL,'Muziek raakt mensen op een manier die woorden alleen niet kunnen. Als muzikant of zanger draag jij bij aan een dienst waar mensen God écht ontmoeten.','Wekelijks of om de week meespelen of meezingen. Aanwezig bij de repetitie op zaterdagavond of zondagochtend. Liedkeuze afstemmen met de dirigent of worship leader.','Een informeel gesprek met de muziekleider en één keer meerepetitie bijwonen.','Muziekleider','muziek@ngkmiddelharnis.nl','active','2026-07-08T14:07:04.189Z','2026-07-08T14:07:04.189Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5jbpg001i7sq18ehi10t2','cmqwsfpam00015gq1re0l6z85','Koffie schenken na de dienst','Praktisch','Jij zorgt na de dienst voor koffie, thee en een warm welkom — het moment waarop de gemeente echt gemeenschap beleeft.',NULL,'Het kopje koffie na de dienst is voor veel mensen het moment van verbinding. Jij maakt dat moment mogelijk en geeft mensen het gevoel dat ze welkom zijn.','Vóór de dienst koffie zetten en klaarleggen. Na de dienst uitschenken en zorgen dat iedereen iets krijgt. Opruimen na afloop. Eens in de zoveel weken, in een rooster.','Een keer meelopen met iemand die het al doet.','Diaconie ','diaconie@ngkmiddelharnis.nl','active','2026-07-08T14:07:07.012Z','2026-07-08T14:07:07.012Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5jdos001r7sq1f2j8a8ki','cmqwsfpam00015gq1re0l6z85','Verwelkoming bij de ingang','Praktisch','Jij staat bij de deur, begroet mensen bij binnenkomst en zorgt dat iedereen — ook nieuwe bezoekers — zich gezien en welkom voelt.',NULL,'De eerste indruk van de kerk begint bij de deur. Een warme begroeting kan het verschil maken voor iemand die voor het eerst komt of al een tijd wegbleef.','Op tijd aanwezig bij de ingang. Mensen begroeten met een glimlach. Nieuwe bezoekers actief opvangen en eventueel doorverwijzen. Liturgieblaadjes uitdelen.','Een keer samen staan met een ervaren verwelkomer.','Gastvrouwcoördinator','gastvrijheid@ngkmiddelharnis.nl','active','2026-07-08T14:07:09.580Z','2026-07-08T14:07:09.580Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5jfq4001y7sq1jz7sruz9','cmqwsfpam00015gq1re0l6z85','Voorlezer in de dienst','Muziek & eredienst','Jij leest de Bijbeltekst voor tijdens de zondagsdienst — duidelijk, rustig en met aandacht voor de inhoud.',NULL,'De Bijbellezing is het hart van de dienst. Een goede voorlezer geeft de tekst de ruimte die hij verdient en helpt de gemeente om echt te luisteren.','De lezing vooraf ontvangen en voorbereiden. Op zondag de tekst voorlezen vanuit de kansel of lezenaar. Eventueel deelnemen aan een korte training voorlezen.','Een gesprek met de ouderling van dienst en één keer oefenen in de kerkzaal.','Ron','rd.lekkerkerk@outlook.com','active','2026-07-08T14:07:12.220Z','2026-07-08T14:07:12.220Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5jisl00247sq1sb5t56i6','cmqwsfpam00015gq1re0l6z85','Missionair denker','Bestuur','Jij denkt mee over hoe de kerk zichtbaar en bereikbaar kan zijn voor mensen buiten de gemeente — en zet dat om in concrete ideeën en initiatieven.',NULL,'De kerk bestaat niet alleen voor zichzelf. Jij helpt nadenken over hoe we als gemeente present kunnen zijn in Middelharnis — met liefde en zonder agenda.','Deelnemen aan het missionair beraad of werkgroep. Ideeën aandragen en uitwerken. Contact leggen met mensen en initiatieven buiten de kerk. Trends signaleren.','Een gesprek met de predikant over de missionaire visie van de gemeente.','Predikant','predikant@ngkmiddelharnis.nl','active','2026-07-08T14:07:16.197Z','2026-07-08T14:07:16.197Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5jlg7002d7sq1n56t4sse','cmqwsfpam00015gq1re0l6z85','Gavencoördinator','Bestuur','Jij helpt gemeenteleden hun gaven en talenten te ontdekken en te verbinden aan vrijwilligersplekken binnen de gemeente.',NULL,'Veel mensen willen bijdragen maar weten niet hoe of waar. Als gavencoördinator ben jij de verbindingspersoon die mensen en taken bij elkaar brengt.','Gesprekken voeren met gemeenteleden over hun gaven. Overzicht bijhouden van openstaande vrijwilligersplekken. Samenwerken met ouderlingen en taakcoördinatoren. Dit programma beheren.','Een gesprek met de kerkenraad over de rol en wat er al is.','Ouderling gemeenteopbouw','opbouw@ngkmiddelharnis.nl','active','2026-07-08T14:07:19.639Z','2026-07-08T14:07:19.639Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5jnt2002m7sq1e5wij6ez','cmqwsfpam00015gq1re0l6z85','Hulpkoster','Praktisch','Jij ondersteunt de koster bij de praktische voorbereiding en afwikkeling van kerkdiensten en andere activiteiten.',NULL,'Zonder goede voorbereiding achter de schermen loopt een dienst niet soepel. Jij zorgt dat alles op zijn plek staat zodat anderen zich kunnen richten op inhoud en ontmoeting.','Kerkzaal klaarzetten voor de dienst — stoelen, microfoons, avondmaalstafel. Na afloop opruimen. Sleutelbeheer en afsluiting van het gebouw.','Een keer meedraaien met de huidige koster.','Koster','koster@ngkmiddelharnis.nl','active','2026-07-08T14:07:22.694Z','2026-07-08T14:07:22.694Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5jpkq002v7sq1e1k0ozfm','cmqwsfpam00015gq1re0l6z85','Klusjesman/vrouw','Praktisch','Jij voert kleine onderhoudsklusjes uit aan het kerkgebouw — van een lekkende kraan tot het ophangen van een whiteboard.',NULL,'Een goed onderhouden gebouw is een teken van rentmeesterschap en zorgt dat iedereen er prettig en veilig kan zijn. Jij houdt het allemaal draaiende.','Kleine reparaties en onderhoudswerkzaamheden uitvoeren. Signaleren wat er moet gebeuren. Afstemmen met de koster en het gebouwbeheer.','Een rondleiding door het gebouw met de koster om te zien wat er speelt.','Koster','koster@ngkmiddelharnis.nl','active','2026-07-08T14:07:24.986Z','2026-07-08T14:07:24.986Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Vacancy" (id,"organizationId",title,category,"shortDescription","longDescription","whyValuable","concreteTasks","firstStep","contactPersonName","contactPersonEmail",status,"createdAt","updatedAt") VALUES ('cmrc5jrup00327sq1xjx46i94','cmqwsfpam00015gq1re0l6z85','Bezoekbroeder/zuster','Pastoraat','Jij bezoekt gemeenteleden thuis — luistert, bemoedigt en bent present namens de gemeente. Je werkt met circa 10 adressen in een pastoraal team.',NULL,'Veel mensen in de gemeente voelen zich eenzaam of hebben behoefte aan een luisterend oor. Jij brengt de gemeente naar mensen toe — dat is kerk in de meest concrete zin.','Regelmatig huisbezoeken afleggen bij jouw adressen (eens per kwartaal of vaker indien nodig). Deelnemen aan het pastorale team. Terugkoppelen aan de wijkouderling.','Een gesprek met de wijkouderling en indien gewenst één gezamenlijk bezoek als kennismaking.','Wijkouderling','pastoraat@ngkmiddelharnis.nl','active','2026-07-08T14:07:27.937Z','2026-07-08T14:07:27.937Z') ON CONFLICT (id) DO NOTHING;
